#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, M;
        scanf("%lld %lld", &N, &M);
        long long ans = 5LL * N + 7LL * M;
        printf("%lld\n", ans);
    }
    return 0;
}

